const fs = require\('fs'\);
const html = fs.readFileSync\('index.html', 'utf8'\);

function normalizeName\(s\) {
  return \(s||''\).normalize\('NFD'\).replace\(/[\\u0300-\\u036f]/g,''\).toLowerCase\(\).trim\(\);
}

