// ALL_PLAYERS has 'Luis Garcia Jr.' \(mlbId 671277\) and 'Luis Garcia' \(mlbId 677651\)
// normalizeName\('Luis Garcia'\) = 'luis garcia'
// normalizeName\('Luis Garcia Jr.'\) = 'luis garcia jr.'  -- different
// So roster 'Luis Garcia' matches AP 'Luis Garcia' \(677651\) - the HOU pitcher \(SP\)
// But the roster player is from team HOU and is SP, which is Luis Garcia Jr. \(671277\)

console.log\('Roster name normalized:', normalizeName\('Luis Garcia'\)\);
console.log\('AP Luis Garcia Jr. normalized:', normalizeName\('Luis Garcia Jr.'\)\);
console.log\('AP Luis Garcia normalized:', normalizeName\('Luis Garcia'\)\);
console.log\(\);
